1. Write a program to implement framing. 
i. Fixed framing, ii. Variable framings

i.Fixed Framing:

#include <stdio.h>
#include <string.h>
#define FRAME_SIZE 4
int main() {
    char data[100];
    int i, len;
    printf("Enter data: ");
    fgets(data, sizeof(data), stdin);
    len = strlen(data);
    if(data[len-1] == '\n') data[len-1] = '\0'; // Remove newline
    len = strlen(data);
    printf("Fixed frames (size = %d):\n", FRAME_SIZE);
    for (i = 0; i < len; i++) {
        printf("%c", data[i]);
        if ((i+1) % FRAME_SIZE == 0) {
            printf(" | ");  // frame boundary
        }
    }
    if (len % FRAME_SIZE != 0) {
        printf(" |"); // end last partial frame
    }
    printf("\n");
    return 0;
}

ii.Variable Framing:

#include<stdio.h>
#include <string.h>
void variable_framing(char *data) 
 {
    int i;
    printf("Variable Framing Output:\n");

    for (i = 0; data[i] != '\0'; i++) {
        printf("%c", data[i]);
        if (data[i] == '*') {
            printf(" | ");  // Frame boundary after delimiter
        }
    }
    printf("\n");
}

int main() {
    char data[100];
    printf("Enter data with '*' as frame delimiter: ");
    fgets(data, sizeof(data), stdin);
    data[strcspn(data, "\n")] = 0;  // Remove newline
    variable_framing(data);
    return 0;
}

